1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_SURCHARGE = 10;
3	const BLOCK_OF_THREE_PREMIUM = 60;
4	const BLOCK_SIZE = 3;
5	const CURSE_SURCHARGE_RATE = 0.5;
6	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
7	const HIGH_ENCHANTMENT_THRESHOLD = 5;
8	
9	const BASE_PREMIUMS: Record<string, number> = {
10	  sword: 100,
11	  amulet: 60,
12	  staff: 80,
13	  potion: 40,
14	  rune: 25,
15	  moonstone: 25,
16	};
17	
18	type Item = { type: string; cursed?: boolean; enchantment?: number };
19	
20	function isHighlyEnchanted(item: Item): boolean {
21	  return item.enchantment !== undefined && item.enchantment >= HIGH_ENCHANTMENT_THRESHOLD;
22	}
23	
24	function surchargeRate(item: Item): number {
25	  return (item.cursed ? CURSE_SURCHARGE_RATE : 0)
26	    + (isHighlyEnchanted(item) ? HIGH_ENCHANTMENT_SURCHARGE_RATE : 0);
27	}
28	
29	function itemBasePremium(item: Item): number {
30	  const base = BASE_PREMIUMS[item.type];
31	  return base + base * surchargeRate(item);
32	}
33	
34	function sumIndividualBasePremiums(items: Item[]): number {
35	  return items.reduce((sum, item) => sum + itemBasePremium(item), 0);
36	}
37	
38	function groupByType(items: Item[]): Record<string, Item[]> {
39	  const groups: Record<string, Item[]> = {};
40	  for (const item of items) {
41	    if (!groups[item.type]) groups[item.type] = [];
42	    groups[item.type].push(item);
43	  }
44	  return groups;
45	}
46	
47	function premiumForGroup(groupItems: Item[]): number {
48	  return groupItems.length === BLOCK_SIZE
49	    ? BLOCK_OF_THREE_PREMIUM
50	    : sumIndividualBasePremiums(groupItems);
51	}
52	
53	function calculateBasePremium(items: Item[]): number {
54	  const groups = groupByType(items);
55	  return Object.values(groups).reduce((total, group) => total + premiumForGroup(group), 0);
56	}
57	
58	export function quote({ items }: { items: Item[]; years: number; priorContract: boolean }): { premium: number } {
59	  const basePremium = calculateBasePremium(items);
60	  const firstInsuranceSurcharges = items.length * FIRST_INSURANCE_SURCHARGE;
61	  return { premium: basePremium + firstInsuranceSurcharges + PROCESSING_FEE };
62	}
63	
64	export function claim(_input: unknown): unknown {
65	  return undefined;
66	}
